def extract_video_id(url: str) -> str | None:
    """Robustly extract a YouTube video ID from common URL forms."""
    try:
        parsed = urlparse(url)
        host = parsed.netloc.lower()
        if "youtu.be" in host:
            vid = parsed.path.strip("/").split("/")[0]
            return vid if vid else None
        if "youtube.com" in host:
            qs = parse_qs(parsed.query)
            if "v" in qs and qs["v"]:
                return qs["v"][0]
            # Shorts format: /shorts/<id>
            m = re.search(r"/shorts/([A-Za-z0-9_-]{6,})", parsed.path)
            if m:
                return m.group(1)
            # Embed format: /embed/<id>
            m = re.search(r"/embed/([A-Za-z0-9_-]{6,})", parsed.path)
            if m:
                return m.group(1)
        # Raw ID?
        if re.fullmatch(r"[A-Za-z0-9_-]{6,}", url.strip()):
            return url.strip()
    except Exception:
        return None
    return None


@lru_cache(maxsize=8)
def fetch_metadata(video_url: str) -> dict:
    """Get title/channel/duration without downloading the media."""
    ydl_opts = {"quiet": True, "skip_download": True}
    with yt_dlp.YoutubeDL(ydl_opts) as ydl:
        info = ydl.extract_info(video_url, download=False)
    return {
        "title": info.get("title"),
        "uploader": info.get("uploader"),
        "duration": info.get("duration"),  # seconds
    }


@lru_cache(maxsize=16)
def fetch_transcript_text(video_id: str, prefer_langs=("en", "en-US")) -> str:
    """
    Try to fetch human or auto-generated transcripts.
    If not available in English, try translating to English when possible.
    """
    # 1) Try preferred languages directly
    try:
        transcript_list = YouTubeTranscriptApi.list_transcripts(video_id)
        for lang in prefer_langs:
            try:
                t = transcript_list.find_transcript([lang]).fetch()
                return " ".join([x["text"] for x in t if x["text"].strip()])
            except Exception:
                pass
    except (NoTranscriptFound, TranscriptsDisabled, VideoUnavailable):
        pass
    except Exception:
        pass

    # 2) Try any transcript, then translate to English if supported
    try:
        transcript_list = YouTubeTranscriptApi.list_transcripts(video_id)
        for tr in transcript_list:
            try:
                t = tr.fetch()
                text = " ".join([x["text"] for x in t if x["text"].strip()])
                if (tr.language_code or "").startswith("en"):
                    return text
                if tr.is_translatable:
                    t_en = transcript_list.find_transcript([tr.language_code]).translate("en").fetch()
                    return " ".join([x["text"] for x in t_en if x["text"].strip()])
                return text
            except Exception:
                continue
    except (NoTranscriptFound, TranscriptsDisabled, VideoUnavailable) as e:
        raise e

    raise NoTranscriptFound("No transcripts available for this video.")


def seconds_to_hms(s: int | None) -> str:
    if not s:
        return "Unknown"
    h = s // 3600
    m = (s % 3600) // 60
    sec = s % 60
    if h:
        return f"{h:d}h {m:02d}m {sec:02d}s"
    return f"{m:d}m {sec:02d}s"


def summarize_to_bullets_lexrank(text: str, desired_points: int = 8) -> list[str]:
    """
    Extractive summary using LexRank (Sumy). Returns bullet sentences.
    """
    text = re.sub(r"\s+", " ", text).strip()
    if not text:
        return []

    parser = PlaintextParser.from_string(text, Tokenizer("english"))
    summarizer = LexRankSummarizer()

    # LexRank returns the "most central" sentences; request a few more than needed, then trim.
    k = max(5, min(20, desired_points + 4))
    summary_sentences = summarizer(parser.document, k)

    # Turn into strings, dedupe, and trim to desired_points
    seen = set()
    bullets = []
    for s in summary_sentences:
        ss = str(s).strip()
        ss = re.sub(r"\s+", " ", ss)
        key = ss.lower()
        if len(ss) < 8 or key in seen:
            continue
        seen.add(key)
        bullets.append(ss)
        if len(bullets) >= desired_points:
            break

    # If still short (very small transcript), just split by sentences
    if len(bullets) < desired_points:
        extra = re.split(r"(?<=[\.\!\?])\s+", text)
        for e in extra:
            e = e.strip()
            if len(e) > 8 and e.lower() not in seen:
                bullets.append(e)
                seen.add(e.lower())
                if len(bullets) >= desired_points:
                    break

    # Wrap for readability in Streamlit
    wrapped = [" ".join(textwrap.wrap(b, width=110)) for b in bullets]
    return wrapped


