    # Show metadata
    try:
        meta = fetch_metadata(url.strip())
        with st.expander("Video details", expanded=True):
            st.markdown(f"**Title:** {meta.get('title','Unknown')}")
            st.markdown(f"**Channel:** {meta.get('uploader','Unknown')}")
            st.markdown(f"**Duration:** {seconds_to_hms(meta.get('duration'))}")
    except Exception:
        pass

    # Fetch transcript & summarize
    try:
        with st.spinner("Fetching transcript…"):
            transcript = fetch_transcript_text(vid)

        with st.spinner("Summarizing…"):
            bullets = summarize_to_bullets_lexrank(transcript, desired_points=desired_points)

        if bullets:
            st.subheader("Summary")
            st.markdown("\n".join([f"- {b}" for b in bullets]))

